interface IngItem { id: number; amount: string; unit: string }
interface DishDef {
  name: string; desc: string; catId: number; time: number; diff: number; serv: number;
  stepList: string[]; ingList: IngItem[]; tagList: string[];
}

function rand(a: number, b: number): number { return Math.floor(Math.random() * (b - a + 1)) + a; }

const SEASONING_POOL: IngItem[] = [
  { id: 20, amount: "1", unit: "\u52fa" }, { id: 21, amount: "1", unit: "\u52fa" },
  { id: 22, amount: "1", unit: "\u5c0f\u52fa" }, { id: 23, amount: "1", unit: "\u5c0f\u52fa" },
  { id: 24, amount: "1", unit: "\u52fa" }, { id: 25, amount: "2", unit: "\u52fa" },
  { id: 17, amount: "3", unit: "\u74e3" }, { id: 18, amount: "3", unit: "\u7247" },
  { id: 19, amount: "2", unit: "\u6839" },
];

function baseIngs(main: IngItem[]): IngItem[] {
  const pool = [...SEASONING_POOL];
  for (let i = pool.length - 1; i > 0; i--) { const j = rand(0, i); [pool[i], pool[j]] = [pool[j], pool[i]]; }
  return [...main, ...pool.slice(0, rand(3, 5))];
}

function d(name: string, desc: string, catId: number, time: number, diff: number, serv: number,
  st: string[], mainIngs: IngItem[], tg: string[]): DishDef {
  return { name, desc, catId, time, diff, serv, stepList: st, ingList: baseIngs(mainIngs), tagList: tg };
}

